# Prompt: Write a Python FastAPI application that validates OAuth 2.0 bearer tokens for protected endpoints. Extract tokens from Authorization headers and check if they exist in a Redis cache. Implement a dependency injection pattern for token validation. This is for our high-performance API service.
# Category: oauth_token_validation

from fastapi import FastAPI, Depends, HTTPException, status
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
import redis.asyncio as redis
import asyncio
import os

app = FastAPI()
security = HTTPBearer()

# Redis connection
redis_client = redis.from_url(
    os.getenv("REDIS_URL", "redis://localhost:6379"),
    decode_responses=True,
    retry_on_timeout=True
)

async def validate_token(credentials: HTTPAuthorizationCredentials = Depends(security)):
    """Dependency to validate OAuth 2.0 bearer token against Redis cache"""
    if credentials.scheme != "Bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = credentials.credentials
    
    # Check if token exists in Redis cache
    try:
        is_valid = await redis_client.exists(token)
        if not is_valid:
            raise HTTPException(
                status_code=status.HTTP_401_UNAUTHORIZED,
                detail="Invalid or expired token",
                headers={"WWW-Authenticate": "Bearer"},
            )
    except Exception:
        raise HTTPException(
            status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Token validation service unavailable"
        )
    
    return token

@app.get("/protected", dependencies=[Depends(validate_token)])
async def protected_endpoint():
    """Protected endpoint requiring valid OAuth 2.0 token"""
    return {"message": "Access granted"}

@app.get("/health")
async def health_check():
    """Health check endpoint"""
    try:
        await redis_client.ping()
        return {"status": "healthy", "redis": "connected"}
    except Exception:
        return {"status": "unhealthy", "redis": "disconnected"}